<script setup lang="ts">
import { computed, onMounted, reactive, ref, watch } from "vue";
import { ElMessage } from "element-plus";
import { api, type PlatformUser, type TeamMemberItem, type TeamSummary } from "../api";
const props = defineProps<{ ownerUserId?: number | null; ownerMemberId?: number | null; adminMode: boolean }>();
const teams=ref<TeamSummary[]>([]), selectedId=ref<number|null>(null), members=ref<TeamMemberItem[]>([]), models=ref<string[]>([]), allModels=ref<string[]>([]), users=ref<PlatformUser[]>([]), loading=ref(false); const selected=computed(()=>teams.value.find(t=>t.teamId===selectedId.value)??null);
const teamForm=reactive({ organizationId:1,name:"",ownerUserId:null as number|null,keyRpm:60,teamRpm:600,teamConcurrency:20,modelConcurrency:50 }); const grant=reactive({modelNames:[] as string[],tokenAllocation:100000,reason:"",expiresAt:""}); const access=reactive({memberId:0,modelNames:[] as string[],tokenAllocation:10000,reason:""}); const dialog=ref<"team"|"edit"|"grant"|"access"|null>(null);
async function load(){loading.value=true;try{const [t,m,u]=await Promise.all([api.teams({page:0,size:100,ownerUserId:props.ownerUserId??null}),api.directModels(),api.users()]);teams.value=t.items;allModels.value=m.items.filter(x=>x.enabled).map(x=>x.modelName);users.value=u.items;if(teams.value.length)await select(teams.value[0].teamId)}catch(e){ElMessage.error(e instanceof Error?e.message:"团队加载失败")}finally{loading.value=false}}
async function select(id:number){selectedId.value=id;const [member,accessData]=await Promise.all([api.members(id),api.teamModels(id)]);members.value=member.items;models.value=accessData.logicalModels}
async function saveTeam(){try{await api.createTeam(teamForm);dialog.value=null;await load();ElMessage.success("团队已创建")}catch(e){ElMessage.error(e instanceof Error?e.message:"创建失败")}}
function openEdit(){if(!selected.value)return;Object.assign(teamForm,selected.value);dialog.value="edit"}
async function saveEdit(){if(!selected.value)return;try{await api.updateTeam(selected.value.teamId,teamForm);dialog.value=null;await load();ElMessage.success("团队已更新")}catch(e){ElMessage.error(e instanceof Error?e.message:"更新失败")}}
async function grantTeam(){if(!selected.value)return;try{await api.grantTeamEntitlement(selected.value.teamId,{...grant,expiresAt:grant.expiresAt||null});dialog.value=null;await select(selected.value.teamId);ElMessage.success("团队模型与额度已发放")}catch(e){ElMessage.error(e instanceof Error?e.message:"发放失败")}}
function openAccess(id:number){access.memberId=id;access.modelNames=[...models.value];dialog.value="access"}
async function saveAccess(){if(!selected.value||!props.ownerMemberId)return;try{await api.grantMemberAccess(selected.value.teamId,access.memberId,{...access,ownerMemberId:props.ownerMemberId});dialog.value=null;ElMessage.success("成员权限和额度已更新，Key 由开发者自行生成")}catch(e){ElMessage.error(e instanceof Error?e.message:"分配失败")}}
watch(()=>[props.ownerUserId,props.ownerMemberId],()=>void load());onMounted(load);
</script>
<template><section class="page-stack" v-loading="loading"><header class="page-heading"><div><p class="eyebrow">Team entitlement</p><h1>{{ adminMode?'企业团队':'我的团队' }}</h1><p>{{ adminMode?'管理员发放团队模型池和公共额度。':'负责人在团队范围内向开发者分配权限与额度。' }}</p></div><el-button v-if="adminMode" type="primary" @click="dialog='team'">新增团队</el-button></header><section class="team-master"><aside class="surface team-list"><div class="compact-list"><button v-for="team in teams" :key="team.teamId" class="list-row" :class="{selected:team.teamId===selectedId}" @click="select(team.teamId)"><strong>{{team.name}}</strong><small>{{team.status}} · {{team.memberCount}} 成员</small></button></div></aside><section v-if="selected" class="surface team-detail"><div class="section-title"><div><h2>{{selected.name}}</h2><p class="muted">负责人 {{selected.ownerName||'未指定'}}</p></div><div><el-button v-if="adminMode" text @click="openEdit">编辑团队</el-button><el-tag>{{selected.status}}</el-tag></div></div><div class="detail-block"><div class="section-title"><h3>团队模型与公共额度</h3><el-button v-if="adminMode" text type="primary" @click="dialog='grant'">主动发放</el-button></div><el-tag v-for="model in models" :key="model" class="app-tag">{{model}}</el-tag><p v-if="!models.length" class="muted">尚未授予模型。</p></div><div class="detail-block"><div class="section-title"><h3>成员授权</h3></div><el-table :data="members" size="small"><el-table-column prop="name" label="成员"/><el-table-column prop="email" label="邮箱"/><el-table-column prop="role" label="角色"/><el-table-column v-if="!adminMode" label="操作"><template #default="scope"><el-button v-if="scope.row.role!=='OWNER'" text type="primary" @click="openAccess(scope.row.memberId)">分配模型和额度</el-button></template></el-table-column></el-table></div></section></section><el-dialog v-model="dialog" :title="dialog==='team'?'新增团队':dialog==='edit'?'编辑团队':dialog==='grant'?'发放团队资源':'分配成员资源'" width="540px"><el-form v-if="dialog==='team'||dialog==='edit'" label-position="top"><el-form-item label="团队名称"><el-input v-model="teamForm.name"/></el-form-item><el-form-item label="Key RPM"><el-input-number v-model="teamForm.keyRpm" :min="1"/></el-form-item><el-form-item label="团队 RPM"><el-input-number v-model="teamForm.teamRpm" :min="1"/></el-form-item></el-form><el-form v-else-if="dialog==='grant'" label-position="top"><el-form-item label="模型"><el-checkbox-group v-model="grant.modelNames"><el-checkbox v-for="m in allModels" :key="m" :label="m">{{m}}</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="额度"><el-input-number v-model="grant.tokenAllocation" :min="1"/></el-form-item><el-form-item label="原因"><el-input v-model="grant.reason"/></el-form-item></el-form><el-form v-else label-position="top"><el-form-item label="模型"><el-checkbox-group v-model="access.modelNames"><el-checkbox v-for="m in models" :key="m" :label="m">{{m}}</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="额度"><el-input-number v-model="access.tokenAllocation" :min="1"/></el-form-item><el-form-item label="说明"><el-input v-model="access.reason"/></el-form-item></el-form><template #footer><el-button @click="dialog=null">取消</el-button><el-button type="primary" @click="dialog==='team'?saveTeam():dialog==='edit'?saveEdit():dialog==='grant'?grantTeam():saveAccess()">保存</el-button></template></el-dialog></section></template>
